insert into reviews (place_id, source_review_id, author_name, rating, review_text, review_time, status) values
  ('ChIJSample001', 'google_review_001', 'Nguyễn Văn An', 5, 'Khách sạn tuyệt vời, phòng sạch sẽ và nhân viên rất thân thiện. Sẽ quay lại lần sau!', '2026-05-10 08:30:00+00', 'pending'),
  ('ChIJSample001', 'google_review_002', 'Trần Thị Bình', 4, 'Vị trí đẹp, gần trung tâm. Bữa sáng khá ngon nhưng check-in hơi chậm.', '2026-05-11 09:15:00+00', 'pending'),
  ('ChIJSample001', 'google_review_003', 'Lê Hoàng Nam', 2, 'Phòng có mùi ẩm, điều hòa không hoạt động tốt. Dịch vụ cần cải thiện nhiều hơn.', '2026-05-12 14:00:00+00', 'pending'),
  ('ChIJSample001', 'google_review_004', 'Phạm Thị Lan', 5, 'Trải nghiệm hoàn hảo từ đầu đến cuối. Nhân viên lễ tân cực kỳ nhiệt tình và chu đáo.', '2026-05-13 10:45:00+00', 'resolved'),
  ('ChIJSample001', 'google_review_005', 'Hoàng Minh Tuấn', 3, 'Phòng ổn, giá hợp lý. Tuy nhiên wifi yếu và hồ bơi đóng cửa không báo trước.', '2026-05-14 16:20:00+00', 'pending'),
  ('ChIJSample001', 'google_review_006', 'Võ Thị Hương', 1, 'Đặt phòng deluxe nhưng lại được xếp phòng standard. Nhân viên không chịu hỗ trợ giải quyết.', '2026-05-15 11:00:00+00', 'pending'),
  ('ChIJSample001', 'google_review_007', 'Đặng Quốc Hùng', 4, 'Không gian sang trọng, view đẹp. Nhà hàng trong khách sạn có món ăn rất ngon.', '2026-05-16 19:30:00+00', 'pending'),
  ('ChIJSample001', 'google_review_008', 'Bùi Thị Mai', 5, 'Lần thứ 3 tôi quay lại đây và chưa bao giờ thất vọng. Chất lượng luôn ổn định.', '2026-05-17 08:00:00+00', 'resolved'),
  ('ChIJSample001', 'google_review_009', 'Ngô Thanh Tùng', 2, 'Giá cao nhưng chất lượng không tương xứng. Phòng tắm cũ kỹ và nước nóng chập chờn.', '2026-05-18 13:10:00+00', 'pending'),
  ('ChIJSample001', 'google_review_010', 'Lý Thị Ngọc', 4, 'Khách sạn đẹp, nhân viên chuyên nghiệp. Chỉ tiếc là bãi đỗ xe hơi chật.', '2026-05-19 17:45:00+00', 'pending');
